from functools import lru_cache


def regex_match(text: str, pattern: str) -> bool:

    @lru_cache(maxsize=None)
    def dp(i: int, j: int) -> bool:
        # Base case: both exhausted
        if j == len(pattern):
            return i == len(text)

        # Check if current characters match (first char match)
        first_match = i < len(text) and (pattern[j] == text[i] or pattern[j] == '.')

        # Handle '*' -- zero or more of preceding element
        if j + 1 < len(pattern) and pattern[j + 1] == '*':
            # Zero occurrences: skip pattern[j] and pattern[j+1] ('*')
            # One or more: consume text[i] if first_match, stay on same pattern
            return dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            # No '*' — must match current character
            return first_match and dp(i + 1, j + 1)

    return dp(0, 0)

