from collections import deque


def topological_sort(n: int, edges: List[Tuple[int, int]]) -> Optional[List[int]]:
    adj: Dict[int, List[int]] = {i: [] for i in range(n)}
    in_degree = [0] * n

    for u, v in edges:
        adj[u].append(v)
        in_degree[v] += 1

    queue = deque([i for i in range(n) if in_degree[i] == 0])
    result = []

    while queue:
        u = queue.popleft()
        result.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if len(result) != n:
        return None
    return result

