from typing import Tuple
from functools import lru_cache


def regex_match(text: str, pattern: str) -> bool:

    @lru_cache(maxsize=None)
    def dp(i: int, j: int) -> bool:
        # Base case: both exhausted
        if j == len(pattern):
            return i == len(text)

        # Check if current characters match (first char match)
        first_match = i < len(text) and (pattern[j] == text[i] or pattern[j] == '.')

        # Handle '*' -- zero or more of preceding element
        if j + 1 < len(pattern) and pattern[j + 1] == '*':
            # Zero occurrences: skip pattern[j] and pattern[j+1] ('*')
            # One or more: consume text[i] if first_match, stay on same pattern
            return dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            # No '*' — must match current character
            return first_match and dp(i + 1, j + 1)

    return dp(0, 0)

from typing import List, Tuple
from collections import deque


def shortest_path_in_maze(
    maze: List[List[int]],
    start: Tuple[int, int],
    end: Tuple[int, int]
) -> List[Tuple[int, int]]:
    if not maze or not maze[0]:
        return []
    rows, cols = len(maze), len(maze[0])

    if maze[start[0]][start[1]] == 1 or maze[end[0]][end[1]] == 1:
        return []

    if start == end:
        return [start]

    queue = deque([start])
    visited = {start}
    parent: Dict[Tuple[int, int], Tuple[int, int]] = {start: None}  # type: ignore

    while queue:
        r, c = queue.popleft()

        if (r, c) == end:
            path = []
            curr: Tuple[int, int] = (r, c)
            while curr is not None:
                path.append(curr)
                curr = parent[curr]
            return path[::-1]

        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            neighbor = (nr, nc)
            if 0 <= nr < rows and 0 <= nc < cols and maze[nr][nc] == 0 and neighbor not in visited:
                visited.add(neighbor)
                parent[neighbor] = (r, c)
                queue.append(neighbor)

    return []

