from typing import List
import bisect


def longest_increasing_subsequence(nums: List[int]) -> int:
    # tails[i] = smallest possible tail value for an LIS of length i+1
    tails: List[int] = []

    for x in nums:
        # Find the first tail >= x (for strictly increasing, use bisect_left)
        # For strictly increasing, we replace the first element >= x
        idx = bisect.bisect_left(tails, x)
        if idx == len(tails):
            tails.append(x)
        else:
            tails[idx] = x

    return len(tails)

from typing import List, Optional
import heapq


class ListNode:
    def __init__(self, val: int = 0, next: Optional['ListNode'] = None):
        self.val = val
        self.next = next


def merge_k_lists(lists: List[Optional[ListNode]]) -> Optional[ListNode]:
    dummy = ListNode(0)
    curr = dummy

    # Min-heap of (value, list_index, node)
    # list_index is used to break ties since ListNode is not comparable
    heap: List[tuple] = []

    for i, node in enumerate(lists):
        if node:
            heapq.heappush(heap, (node.val, i, node))

    while heap:
        val, i, node = heapq.heappop(heap)
        curr.next = node
        curr = curr.next

        if node.next:
            heapq.heappush(heap, (node.next.val, i, node.next))

    return dummy.next

from typing import List, Tuple


def matrix_chain_order(dims: List[int]) -> Tuple[int, List[int]]:
    n = len(dims) - 1  # number of matrices
    if n <= 1:
        return 0, []

    # dp[i][j] = min cost to multiply matrices i..j (inclusive)
    dp = [[0] * n for _ in range(n)]
    # split[i][j] = optimal split point k for matrices i..j
    split = [[0] * n for _ in range(n)]

    # Length of chain (L = 2 to n)
    for L in range(2, n + 1):
        for i in range(n - L + 1):
            j = i + L - 1
            dp[i][j] = float('inf')
            for k in range(i, j):
                cost = (dp[i][k] + dp[k + 1][j]
                        + dims[i] * dims[k + 1] * dims[j + 1])
                if cost < dp[i][j]:
                    dp[i][j] = cost
                    split[i][j] = k

    # Collect splits in order of the DP traversal
    split_order: List[int] = []
    for L in range(2, n + 1):
        for i in range(n - L + 1):
            j = i + L - 1
            if L >= 2:
                split_order.append(split[i][j])

    return dp[0][n - 1], split_order

